#!/usr/bin/env perl
use strict;
use warnings;

use Cwd qw(abs_path);
use Encode qw(FB_DEFAULT decode encode encode_utf8);
use Fcntl qw(O_NOFOLLOW O_NONBLOCK O_RDONLY S_ISREG);
